import React, { useState, useEffect, useRef } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import Webcam from "react-webcam";
// Ensure this points exactly to your axios.js file in the api folder
import axios from '../api/axios'; 

const StudyRoom = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const webcamRef = useRef(null);

    const [seconds, setSeconds] = useState(10); // Set to 10 for quick testing
    const [isActive, setIsActive] = useState(false);
    const [showExplanation, setShowExplanation] = useState(false);
    const [explanation, setExplanation] = useState("");

    useEffect(() => {
        let interval = null;
        if (isActive && seconds > 0) {
            interval = setInterval(() => setSeconds(s => s - 1), 1000);
        } else if (seconds === 0) {
            clearInterval(interval);
            setIsActive(false);
            setShowExplanation(true); 
        }
        return () => clearInterval(interval);
    }, [isActive, seconds]);

    const handleFinish = async () => {
        try {
            // Using your custom axios instance to update the task
            // The baseURL is likely already set in your ../api/axios.js
            await axios.patch(`/tasks/${id}`, { 
                status: 'completed',
                userExplanation: explanation 
            });
            
            // Redirect back to planPage
            navigate('/planPage');
        } catch (error) {
            console.error("Save failed:", error);
            // Fallback redirect if backend isn't ready, so you aren't stuck
            navigate('/planPage'); 
        }
    };

    const formatTime = (secs) => {
        const mins = Math.floor(secs / 60);
        const s = secs % 60;
        return `${mins}:${s < 10 ? '0' : ''}${s}`;
    };

    return (
        <div style={{ textAlign: 'center', padding: '40px' }}>
            {!showExplanation ? (
                <>
                    <h2>Study Session Active</h2>
                    <div style={{ width: '400px', margin: '20px auto', borderRadius: '15px', overflow: 'hidden', border: '3px solid #2c3e50' }}>
                        <Webcam audio={false} ref={webcamRef} width="100%" />
                    </div>
                    <div style={{ fontSize: '5rem', fontWeight: 'bold', margin: '20px' }}>{formatTime(seconds)}</div>
                    <button 
                        onClick={() => setIsActive(!isActive)}
                        style={{ padding: '15px 40px', fontSize: '1.2rem', background: isActive ? '#e74c3c' : '#3498db', color: 'white', border: 'none', borderRadius: '5px', cursor: 'pointer' }}
                    >
                        {isActive ? 'Pause Focus' : 'Start Focus'}
                    </button>
                </>
            ) : (
                <div style={{ maxWidth: '600px', margin: '0 auto', background: '#f8f9fa', padding: '30px', borderRadius: '10px' }}>
                    <h2>Time's Up! 🏁</h2>
                    <p>Explain what you learned to complete this day:</p>
                    <textarea 
                        value={explanation}
                        onChange={(e) => setExplanation(e.target.value)}
                        placeholder="Key concepts learned..."
                        style={{ width: '100%', height: '150px', padding: '15px', margin: '20px 0', fontSize: '1rem', borderRadius: '5px', border: '1px solid #ccc' }}
                    />
                    <button 
                        onClick={handleFinish}
                        disabled={!explanation.trim()}
                        style={{ width: '100%', padding: '15px', background: '#28a745', color: 'white', border: 'none', borderRadius: '5px', fontSize: '1.1rem', cursor: 'pointer' }}
                    >
                        Finish & Mark Done
                    </button>
                </div>
            )}
        </div>
    );
};

export default StudyRoom;
